class Solution {
    public int maxSubstrings(String word) {
        int res = 0, i = 0;
        while (i < word.length()) {
            if (i + 3 < word.length() && word.charAt(i) == word.charAt(i + 3)) {
                int j = i + 4;
                while (j < word.length() && word.charAt(j) == word.charAt(i)) j++;
                res++;
                i = j;
            } else {
                i++;
            }
        }
        return res;
    }
}
